async def run(args, state):
    content = str(state.get('content') or '').strip()
    variables = state.get('variables') if isinstance(state.get('variables'), dict) else {}
    query_parts = [content]
    for key in ('page_title', 'docs_path', 'page_url'):
        value = str(variables.get(key) or '').strip()
        if value:
            query_parts.append(value)
    query = '\n'.join(part for part in query_parts if part).strip() or 'Humanitec documentation'
    language = variables.get('docs_language') or variables.get('interface_language_code') or variables.get('user_language') or 'ru'
    result = await capability('tools.docs_prepare_context', query=query, limit=5, language=str(language))
    if not isinstance(result, dict):
        result = {'success': False, 'error': 'docs_prepare_context returned non-object'}
    variables['docs_search_context'] = str(result.get('prompt_context') or '')
    variables['docs_search_links'] = str(result.get('prompt_links') or '')
    variables['docs_search_status'] = 'found' if result.get('results') else 'not_found'
    if not result.get('success', False):
        variables['docs_search_status'] = 'error'
        variables['docs_search_error'] = str(result.get('error') or 'Documentation search failed')
    state['variables'] = variables
    state['docs_search_result'] = result
    return {'variables': variables, 'docs_search_result': result}
